```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.3;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/math/SafeERC20.sol";

contract StakingContract is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    enum State { ReadyToDeposit, Depositing, ReadyToRoll, Rolling }

    IERC20 public token;
    uint256 public currentRound;
    uint256 public readyAt;
    uint256 public roundPricePerShare;
    uint256 public roundDeposited;
    mapping(address => uint256) public shares;

    event Deposit(address indexed user, uint256 amount);
    event Withdraw(address indexed user, uint256 amount);
    event Roll(uint256 indexed round, uint256 pricePerShare);
    event StateTransition(State newState);

    constructor(IERC20 _token) {
        token = _token;
        owner = msg.sender;
        currentRound = 0;
        readyAt = block.timestamp + 1 days; // Initial state is ReadyToDeposit
        roundPricePerShare = 1 ether; // 1 token per share initially
        roundDeposited = 0;
    }

    modifier inState(State expectedState) {
        require(block.timestamp >= readyAt && uint256(State(expectedState)) == uint256(State(currentState)), "Incorrect state");
        _;
    }

    function deposit(uint256 amount) external nonReentrant inState(State.Depositing) {
        require(amount > 0, "Deposit amount must be greater than zero");
        require(token.safeTransferFrom(msg.sender, address(this), amount), "Transfer failed");

        uint256 sharesAmount = amount / roundPricePerShare;
        shares[msg.sender] += sharesAmount;
        roundDeposited += amount;

        emit Deposit(msg.sender, amount);
    }

    function withdraw() external nonReentrant inState(State.ReadyToRoll) {
        uint256 sharesAmount = shares[msg.sender];
        require(sharesAmount > 0, "No shares to withdraw");

        uint256 amount = sharesAmount * roundPricePerShare;
        shares[msg.sender] = 0;
        roundDeposited -= amount;

        require(token.safeTransfer(msg.sender, amount), "Transfer failed");

        emit Withdraw(msg.sender, amount);
    }

    function roll() external onlyOwner inState(State.Rolling) {
        uint256 oldRoundPricePerShare = roundPricePerShare;
        roundPricePerShare = roundDeposited / totalSupply();

        currentRound++;
        readyAt = block.timestamp + 1 days; // Next state is ReadyToDeposit

        emit Roll(currentRound, oldRoundPricePerShare);
        emit StateTransition(State.ReadyToDeposit);
    }

    function getPricePerShare() external view returns (uint256) {
        return roundPricePerShare;
    }

    function totalSupply() public view returns (uint256) {
        return roundDeposited / roundPricePerShare;
    }

    function changeState(State newState) external onlyOwner inState(currentState) {
        require(newState > currentState, "New state must be greater");
        currentState = newState;
        readyAt = block.timestamp + 1 days; // Update readyAt for next state
        emit StateTransition(newState);
    }
}
