pragma solidity ^0.8.3;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/math/SafeERC20.sol";

contract StakingContract is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    enum State { ReadyToDeposit, Depositing, ReadyToRoll, Rolling }

    IERC20 public token;
    uint256 public currentRound;
    uint256 public readyAt;
    uint256 public roundPricePerShare;
    uint256 public roundDeposited;
    mapping(address => uint256) public userBalances;

    event Deposit(address indexed user, uint256 amount);
    event Withdrawal(address indexed user, uint256 amount);
    event Roll(address indexed user);
    event StateTransition(State newState);

    constructor(IERC20 _token) {
        token = _token;
        currentRound = 1;
        readyAt = block.timestamp + 1 days; // Initial state is ReadyToDeposit
        roundPricePerShare = 0;
        roundDeposited = 0;
    }

    modifier inState(State expectedState) {
        require(block.timestamp >= readyAt && uint256(State(currentState)) == uint256(expectedState), "Incorrect state");
        _;
    }

    function deposit(uint256 amount) external nonReentrant {
        require(amount > 0, "Deposit amount must be greater than zero");
        token.safeTransferFrom(msg.sender, address(this), amount);
        userBalances[msg.sender] += amount;
        roundDeposited += amount;
        emit Deposit(msg.sender, amount);
    }

    function withdraw() external nonReentrant {
        uint256 amount = userBalances[msg.sender];
        require(amount > 0, "No balance to withdraw");

        // Zero the balance before the transfer to prevent reentrancy
        userBalances[msg.sender] = 0;

        token.safeTransfer(msg.sender, amount);
        emit Withdrawal(msg.sender, amount);
    }

    function roll() external onlyOwner inState(State.ReadyToRoll) {
        // Roll logic here
        currentRound++;
        readyAt = block.timestamp + 1 days;
        currentState = State.ReadyToDeposit;
        emit Roll(msg.sender);
        emit StateTransition(State.ReadyToDeposit);
